function solve(points, target) {
    // Helper function to check if target is in the current set of points
    const isTargetPresent = (pointSet, targetPoint) => {
        for (const p of pointSet) {
            if (p[0] === targetPoint[0] && p[1] === targetPoint[1] && p[2] === targetPoint[2]) {
                return true;
            }
        }
        return false;
    };

    // --- Step 0: Check initial set (k=0) ---
    const initialSet = new Set();
    for (const p of points) {
        initialSet.add(JSON.stringify(p));
    }

    const targetStr = JSON.stringify(target);
    if (initialSet.has(targetStr)) {
        return 0;
    }

    // Initialize the set of all generated points (starts with initial points)
    // We use a Set of strings for efficient lookup and uniqueness.
    let allPointsStrings = new Set(Array.from(initialSet));

    // Store the actual points array for easy iteration during generation
    let currentPoints = points.map(p => p.join(','));

    let k = 0;
    const MAX_K = 20000; // Safety break, though constraints suggest a smaller bound might suffice.

    while (k < MAX_K) {
        k++;

        const newPoints = [];
        const newPointsSet = new Set();

        // Convert current points strings back to arrays for calculation
        const availablePoints = Array.from(allPointsStrings).map(str => str.split(',').map(Number));

        // The problem states: "Consider from all points generated from generation 0 to k-1"
        // This is equivalent to using all points collected so far (allPointsStrings).

        const n = availablePoints.length;
        if (n < 2) {
            // Cannot form new pairs if less than 2 distinct points exist.
            return -1;
        }

        // Iterate over all pairs (a, b) where a and b are distinct points
        for (let i = 0; i < n; i++) {
            for (let j = i + 1; j < n; j++) {
                const a = availablePoints[i];
                const b = availablePoints[j];

                // Check the distinctness requirement: 
                // "choosing two DIFFERENT points" 
                // "must have DIFFERENT (x, y, z) coordinates"

                // Since availablePoints is derived from allPointsStrings which are unique string representations,
                // if i != j, the points a and b *should* have different coordinates 
                // unless the input generation process somehow created non-unique coordinates, 
                // but the problem implies we are pairing points derived from unique coordinates.

                // Let's explicitly check the coordinates just in case the generation process (if it were recursive) 
                // might allow duplicate coordinate vectors in the set, but given how we build the set, 
                // this check should only be necessary if the problem meant "different instances" vs "different coordinates".
                // "Two different points" usually means different indices in the sequence used for generation, 
                // but the note clarifies: "two different points" means coordinates must differ.

                const areSameCoordinates = (
                    a[0] === b[0] && a[1] === b[1] && a[2] === b[2]
                );

                if (areSameCoordinates) {
                    // This should ideally not happen if allPointsStrings contains only unique coordinate vectors.
                    continue; 
                }

                // Calculate midpoint c
                const c = [
                    Math.floor((a[0] + b[0]) / 2),
                    Math.floor((a[1] + b[1]) / 2),
                    Math.floor((a[2] + b[2]) / 2)
                ];

                const cStr = JSON.stringify(c);

                // Add to new points if it's genuinely new (not generated before)
                if (!allPointsStrings.has(cStr)) {
                    newPoints.push(c);
                    newPointsSet.add(cStr);
                }
            }
        }

        // Update the set of all known points
        for (const p of newPoints) {
            allPointsStrings.add(JSON.stringify(p));
        }

        // --- Check if target was found in this new generation ---
        const targetFoundInGenerationK = newPoints.some(p => 
            p[0] === target[0] && p[1] === target[1] && p[2] === target[2]
        );

        if (targetFoundInGenerationK) {
            return k;
        }

        // If we reached a state where no new points are generated AND the target wasn't found, we can stop.
        if (newPoints.length === 0 && k > 0) {
            return -1;
        }
    }

    return -1; // Reached max iterations without finding target
}

