import java.util.ArrayList;
import java.util.HashSet;
import java.util.List;
import java.util.Set;
import java.util.stream.Collectors;

class Solution {
    /**
     * Helper function to convert an array of integers [x, y, z] to a unique string key.
     */
    private static String pointToString(long[] p) {
        return p[0] + "," + p[1] + "," + p[2];
    }

    /**
     * Helper function to convert a string key back to a long[] point.
     */
    private static long[] stringToPoint(String s) {
        String[] parts = s.split(",");
        return new long[]{
            Long.parseLong(parts[0]),
            Long.parseLong(parts[1]),
            Long.parseLong(parts[2])
        };
    }

    public static int solve(long[][] points, long[] target) {
        // Step 0: Check initial set (k=0)
        Set<String> allPointsSet = new HashSet<>();
        for (long[] p : points) {
            allPointsSet.add(pointToString(p));
        }

        String targetStr = pointToString(target);
        if (allPointsSet.contains(targetStr)) {
            return 0;
        }

        // Set to store all unique points generated so far (including initial points)
        // We use String keys for efficiency.
        // The set starts with all initial points.

        int k = 0;

        // We use a loop that simulates generation k -> k+1
        while (true) {
            k++;

            // List to store new points generated in this iteration (k)
            List<long[]> newPoints = new ArrayList<>();
            Set<String> newPointsSet = new HashSet<>();

            // Collect all unique points available up to generation k-1
            List<long[]> availablePoints = new ArrayList<>();
            for (String pStr : allPointsSet) {
                availablePoints.add(stringToPoint(pStr));
            }

            int n = availablePoints.size();

            if (n < 2) {
                // Cannot form new pairs if less than 2 distinct points exist.
                return -1;
            }

            // Iterate over all pairs (a, b) where a and b are distinct coordinate vectors
            for (int i = 0; i < n; i++) {
                for (int j = i + 1; j < n; j++) {
                    long[] a = availablePoints.get(i);
                    long[] b = availablePoints.get(j);

                    // Requirement: "two different points" must have "different (x, y, z) coordinates".
                    // Since availablePoints is derived from a set of unique coordinate vectors (allPointsSet),
                    // if i != j, the coordinates must be different. We verify this explicitly for safety, 
                    // though it should be guaranteed by how allPointsSet was built.
                    if (a[0] == b[0] && a[1] == b[1] && a[2] == b[2]) {
                        continue; 
                    }

                    // Calculate midpoint c = [floor((x1 + x2) / 2), floor((y1 + y2) / 2), floor((z1 + z2) / 2)]
                    long[] c = new long[3];
                    c[0] = (a[0] + b[0]) / 2; // Integer division in Java acts as floor for positive numbers
                    c[1] = (a[1] + b[1]) / 2;
                    c[2] = (a[2] + b[2]) / 2;

                    String cStr = pointToString(c);

                    // Add to new points if it's genuinely new (not generated before)
                    if (!allPointsSet.contains(cStr) && !newPointsSet.contains(cStr)) {
                        newPoints.add(c);
                        newPointsSet.add(cStr);
                    }
                }
            }

            // Check if target was found in this new generation (newPoints list)
            for (long[] p : newPoints) {
                if (p[0] == target[0] && p[1] == target[1] && p[2] == target[2]) {
                    return k;
                }
            }

            // Update the set of all known points
            for (long[] p : newPoints) {
                allPointsSet.add(pointToString(p));
            }

            // Stop condition: If no new points were generated and the target wasn't found, we are stuck.
            if (newPoints.isEmpty()) {
                return -1;
            }
        }
    }
}
