import java.util.HashSet;
import java.util.Set;
import java.util.ArrayList;
import java.util.List;

class Solution {

    // Helper class to represent a 3D point uniquely for use in Sets/Maps
    private static class Point {
        final int x, y, z;

        Point(int x, int y, int z) {
            this.x = x;
            this.y = y;
            this.z = z;
        }

        @Override
        public boolean equals(Object o) {
            if (this == o) return true;
            if (o == null || getClass() != o.getClass()) return false;
            Point point = (Point) o;
            return x == point.x && y == point.y && z == point.z;
        }

        @Override
        public int hashCode() {
            // Simple combination hash for 3 integers
            return 31 * (31 * x + y) + z;
        }
    }

    /**
     * @param points Initial set of points.
     * @param target The target point.
     * @return The minimum generation k, or -1 if unattainable.
     */
    public static long solve(long[][] points, long[] target) {
        // k=0 check
        Set<Point> currentPoints = new HashSet<>();
        for (long[] p : points) {
            currentPoints.add(new Point((int) p[0], (int) p[1], (int) p[2]));
        }

        Point targetPoint = new Point((int) target[0], (int) target[1], (int) target[2]);

        if (currentPoints.contains(targetPoint)) {
            return 0;
        }

        int k = 0;

        // Since coordinates are small (0 to 6), the number of unique points is small (7^3 = 343).
        // The process must terminate quickly or enter a cycle where no new points are generated.

        while (true) {
            k++;

            List<Point> pointsList = new ArrayList<>(currentPoints);
            int n = pointsList.size();

            if (n < 2) {
                // Cannot form new pairs if less than 2 distinct points exist.
                return -1;
            }

            Set<Point> newPoints = new HashSet<>();
            boolean generatedNewPoint = false;

            // Iterate over all pairs (a, b) where a and b are distinct points (by index)
            for (int i = 0; i < n; i++) {
                for (int j = i + 1; j < n; j++) {
                    Point a = pointsList.get(i);
                    Point b = pointsList.get(j);

                    // The requirement: "choosing two DIFFERENT points" which means coordinates must differ.
                    // Since we store unique points in currentPoints, if i != j, the points a and b must have 
                    // different coordinates by the definition of the Set. We still check explicitly for robustness 
                    // regarding the problem statement's strictness on coordinate difference.
                    if (a.equals(b)) {
                        continue; // Should not happen if pointsList is built from a Set
                    }

                    // Calculate midpoint c = [floor((x1 + x2) / 2), ...]
                    int cx = (int) Math.floor((a.x + b.x) / 2.0);
                    int cy = (int) Math.floor((a.y + b.y) / 2.0);
                    int cz = (int) Math.floor((a.z + b.z) / 2.0);

                    Point c = new Point(cx, cy, cz);

                    // Add to new points only if it's genuinely new (not in currentPoints AND not already slated for this generation)
                    if (!currentPoints.contains(c) && !newPoints.contains(c)) {
                        newPoints.add(c);
                        generatedNewPoint = true;

                        // Check if target was found in this generation
                        if (c.equals(targetPoint)) {
                            return k;
                        }
                    }
                }
            }

            if (!generatedNewPoint && k > 0) {
                // No new unique points were generated, and target wasn't found in this generation.
                return -1;
            }

            // Merge new points into the current set for the next generation
            currentPoints.addAll(newPoints);

            // Safety break for extremely large numbers, although unlikely given constraints
            if (k > 10000) return -1;
        }
    }
}
