                    a[0] === b[0] && a[1] === b[1] && a[2] === b[2]
                );

                if (areSameCoordinates) {
                    // This should ideally not happen if allPointsStrings contains only unique coordinate vectors.
                    continue; 
                }

                // Calculate midpoint c
                const c = [
                    Math.floor((a[0] + b[0]) / 2),
                    Math.floor((a[1] + b[1]) / 2),
                    Math.floor((a[2] + b[2]) / 2)
                ];

                const cStr = JSON.stringify(c);

                // Add to new points if it's genuinely new (not generated before)
                if (!allPointsStrings.has(cStr)) {
                    newPoints.push(c);
                    newPointsSet.add(cStr);
                }
            }
        }

        // Update the set of all known points
        for (const p of newPoints) {
            allPointsStrings.add(JSON.stringify(p));
        }

        // --- Check if target was found in this new generation ---
        const targetFoundInGenerationK = newPoints.some(p => 
            p[0] === target[0] && p[1] === target[1] && p[2] === target[2]
        );

        if (targetFoundInGenerationK) {
            return k;
        }

        // If we reached a state where no new points are generated AND the target wasn't found, we can stop.
        if (newPoints.length === 0 && k > 0) {
            return -1;
        }
    }

    return -1; // Reached max iterations without finding target
}
